// src/lib/plugin.ts
var plugin = (def) => ({
  strict: false,
  alwaysApply: false,
  ...def,
  apply: (cldAsset, ctx) => def.apply(cldAsset, ctx, ctx)
});

// src/plugins/restore.ts
var RestorePlugin = /* @__PURE__ */ plugin({
  name: "Restore",
  supports: "image",
  inferOwnOptions: {},
  props: {
    restore: true
  },
  apply: (cldAsset, opts) => {
    const { restore } = opts;
    if (restore) {
      cldAsset.addTransformation("e_gen_restore");
    }
    return {};
  }
});
export {
  RestorePlugin
};
